  renderer.shadowMap.enabled = rendererCfg.shadowMapEnabled !== false;
  renderer.shadowMap.type = THREE.PCFShadowMap;
  renderer.toneMapping = TONE_MAPPING[rendererCfg.toneMapping] ?? THREE.ACESFilmicToneMapping;
